endpoint.response:
{ success, message, data: { import_run: {
  id, resource, status:'analyzing', original_filename,
  total_rows:0, valid_rows:0, warning_rows:0, error_rows:0,
  duplicate_rows:0, imported_rows:null, modified_rows:0,
  has_error_report:false, created_at
} } }

{ success, message, data: {
  items: Array<{ id, row_number, status, is_edited, duplicate_of_id|null,
                 values: Record, messages: string[] }>,
  pagination: { total, offset, limit, total_pages }
} }

{ success, message, data: { row: { id, row_number, status, is_edited,
  duplicate_of_id|null, values, messages }, counts: { total, valid_rows,
  warning_rows, error_rows, duplicate_rows, modified_rows } } }

{ success, message, data: { summary: {
  total_rows, valid_rows, warning_rows, error_rows, duplicate_rows,
  modified_rows, mapped_fields: Array<{ column:string, field:string }>,
  extra_fields: string[], global_config: Record,
  dedup_strategy, warnings: string[]
} } }
